const amqp = require('amqplib');

async function connectToRabbitMQ() {
  const connection = await amqp.connect('amqp://localhost');
  const channel = await connection.createChannel();
  await channel.assertQueue('payment_events');

  channel.consume('payment_events', async (msg) => {
    if (msg !== null) {
      try {
        const paymentData = JSON.parse(msg.content.toString());
        // Execute payment logic based on message content
        processPayment(paymentData);
        channel.ack(msg);
      } catch (error) {
        console.error('Error processing payment event:', error);
      }
    }
  });

  console.log('Waiting for messages in payment_events queue...');
}

function processPayment(paymentData) {
  // Implement your payment logic here based on paymentData
  console.log('Processing payment:', paymentData);
  // Example payment processing logic
  if (paymentData.amount > 0) {
    console.log('Payment processed successfully');
  } else {
    console.error('Invalid payment amount');
  }
}

connectToRabbitMQ().catch(console.error);